const FOLDER_NAMES = {};
const FOLDER_NAMES_EXPANDED = {};

// Resolve a filename to a vendored icon base name (longest-extension first).
export function iconForFile(name) {
  const lower = String(name).toLowerCase();
  if (FILE_NAMES[lower]) return FILE_NAMES[lower];
  const parts = lower.split('.');
  for (let i = 1; i < parts.length; i++) {
    const ext = parts.slice(i).join('.');
    if (FILE_EXTS[ext]) return FILE_EXTS[ext];
  }
  return 'file';
}
export function iconForFolder(name, expanded) {
  const lower = String(name).toLowerCase();
  const table = expanded ? FOLDER_NAMES_EXPANDED : FOLDER_NAMES;
  if (table[lower]) return table[lower];
  return expanded ? 'folder-open' : 'folder';
}
export function svgFor(icon) { return ICON_SVGS[icon] || ICON_SVGS['file']; }
export function isFolderIcon(icon) { return icon === 'folder' || icon === 'folder-open' || icon === 'folder-root' || icon === 'folder-root-open'; }
